using System.Collections.Generic;
using System.Linq;

public class TraitementLINQ {
    public static int CalculerSommeCarresPairs(IEnumerable<int> nombres) {
        // LINQ avec méthodes d'extension et évaluation différée (Deferred Execution)
        return nombres
            .Where(n => n % 2 == 0)
            .Select(n => n * n)
            .Sum();
    }

    public static Dictionary<bool, List<int>> Partitionner() {
        // Expression de collection moderne C# 12
        int[] source = [1, 2, 3, 4, 5, 6];

        return source
            .GroupBy(n => n % 2 == 0)
            .ToDictionary(g => g.Key, g => g.ToList());
    }
}

