using System.Threading;
using System.Threading.Tasks;

public class ConcurrenceDemo {
    // Méthode asynchrone non-bloquante restituant le thread au ThreadPool pendant le délai
    public static async Task<string> TraiterDonneesAsync(int taskId, CancellationToken ct) {
        // Propagation du jeton d'annulation (CancellationToken)
        await Task.Delay(1000, ct);
        return $"Résultat tâche {taskId}";
    }

    public static async Task ExecuterTraitementMassifAsync() {
        using var cts = new CancellationTokenSource(TimeSpan.FromSeconds(5));

        // Lancement de 10 000 tâches gérées par la TPL et le ThreadPool .NET
        var taches = new Task<string>[10_000];
        for (int i = 0; i < taches.Length; i++) {
            taches[i] = TraiterDonneesAsync(i, cts.Token);
        }

        // Attente asynchrone globale
        string[] resultats = await Task.WhenAll(taches);
        Console.WriteLine($"{resultats.Length} tâches achevées.");
    }
}

