using System;
using System.Reflection;

// 1. Attribut personnalisé pour la métaprogrammation
[AttributeUsage(AttributeTargets.Property)]
public class ValiderLongueurAttribute : Attribute {
    public int Max { get; }
    public ValiderLongueurAttribute(int max) => Max = max;
}

// 2. Classe générique avec contraintes et conservation du type réel au runtime
public class InspecteurGénérique<T> where T : class {

    public static void AnalyserEtValider(T instance) {
        // Le type T est RÉIFIÉ : parfaitement connu à l'exécution !
        Type typeReel = typeof(T);
        Console.WriteLine($"Inspection du type réel : {typeReel.FullName}");

        foreach (PropertyInfo prop in typeReel.GetProperties()) {
            var attr = prop.GetCustomAttribute<ValiderLongueurAttribute>();
            if (attr != null && prop.PropertyType == typeof(string)) {
                string? val = prop.GetValue(instance) as string;
                if (val != null && val.Length > attr.Max) {
                    throw new InvalidOperationException($"Champ {prop.Name} trop long !");
                }
            }
        }
    }
}

